package main

import (
	"strings"
	"testing"
)

func TestEmitActiveFallback_LogsWarning(t *testing.T) {
	t.Parallel()

	got := emitActiveFallback("sample", "1.0", "2.0")

	for _, want := range []string{
		"// Code generated by themegen. DO NOT EDIT.",
		"//go:build theme_sample",
		"package theme",
		`"log/slog"`,
		"func init() {",
		`slog.Warn("theme: requested theme not compatible with app version, falling back to default"`,
		`"theme", "sample"`,
		`"theme_min", "2.0"`,
		`"app_version", "1.0"`,
	} {
		if !strings.Contains(got, want) {
			t.Errorf("emitActiveFallback output missing %q\n--- output ---\n%s", want, got)
		}
	}
}

func TestEmitActiveOverride_WithHTTPXOverrides(t *testing.T) {
	t.Parallel()

	got := emitActiveOverride("sample", "github.com/hayakawakaki/go-racp", true)

	for _, want := range []string{
		"// Code generated by themegen. DO NOT EDIT.",
		"//go:build theme_sample",
		"package theme",
		`themessample "github.com/hayakawakaki/go-racp/themes/sample"`,
		`_ "github.com/hayakawakaki/go-racp/themes/sample/platform/httpx"`,
		"func init() {",
		"Active = SampleTheme{}",
		"ActiveName = themessample.ThemeName",
		"ActiveVersion = themessample.ThemeVersion",
		"ActivePageCount = themessample.PageCount",
		"ActiveStatic = themessample.Static",
		"ActiveMountRoutes = themessample.MountRoutes",
		"ActiveAccessYAML = themessample.AccessYAML",
	} {
		if !strings.Contains(got, want) {
			t.Errorf("emitActiveOverride output missing %q\n--- output ---\n%s", want, got)
		}
	}
}

func TestEmitActiveOverride_NoHTTPXSkipsBlankImport(t *testing.T) {
	t.Parallel()

	got := emitActiveOverride("sample", "github.com/hayakawakaki/go-racp", false)

	if strings.Contains(got, "/themes/sample/platform/httpx") {
		t.Errorf("expected no httpx blank-import when hasHTTPXOverrides=false, got:\n%s", got)
	}
	if !strings.Contains(got, "ActiveAccessYAML = themessample.AccessYAML") {
		t.Errorf("expected ActiveAccessYAML rebinding regardless of httpx, got:\n%s", got)
	}
}

func TestEmitActiveDefault_DeclaresDispatchVars(t *testing.T) {
	t.Parallel()

	got := emitActiveDefault("github.com/hayakawakaki/go-racp")

	for _, want := range []string{
		"// Code generated by themegen. DO NOT EDIT.",
		"package theme",
		`themesdefault "github.com/hayakawakaki/go-racp/themes/default"`,
		`_ "github.com/hayakawakaki/go-racp/themes/default/platform/httpx"`,
		"var Active Theme = DefaultTheme{}",
		"DefaultName        = themesdefault.ThemeName",
		"DefaultVersion     = themesdefault.ThemeVersion",
		"DefaultPageCount   = themesdefault.PageCount",
		"DefaultStatic      = themesdefault.Static",
		"DefaultMountRoutes = themesdefault.MountRoutes",
		"DefaultAccessYAML  = themesdefault.AccessYAML",
		"ActiveName        = DefaultName",
		"ActiveVersion     = DefaultVersion",
		"ActivePageCount   = DefaultPageCount",
		"ActiveStatic      = DefaultStatic",
		"ActiveMountRoutes = DefaultMountRoutes",
		"ActiveAccessYAML  = DefaultAccessYAML",
	} {
		if !strings.Contains(got, want) {
			t.Errorf("emitActiveDefault output missing %q\n--- output ---\n%s", want, got)
		}
	}
}
